from copy import deepcopy

from attr import dataclass, field
from BaseClasses import Location, CollectionState
from rule_builder.rules import False_, HasAll, HasGroup
from .items import base_id

@dataclass
class Condition:
    require_all: list[str] = field(factory=list)
    require_any: list[str] = field(factory=list)
    require_none: list[str] = field(factory=list)
    #require_count: dict[str, int] = field(factory=dict)
    required_items: list[str] = field(factory=list)
    required_item_groups: list[str] = field(factory=list)
    def is_fulfilled(self, enabled_entitlements:list[str]):
        if len(self.require_all) != 0 and any(x not in enabled_entitlements for x in self.require_all):
            return False
        if len(self.require_any) != 0 and all(x not in enabled_entitlements for x in self.require_any):
            return False
        if len(self.require_none) != 0 and any(x in enabled_entitlements for x in self.require_none):
            return False
        return True

class HitmanLocation(Location):
    game: str = "HITMAN World of Assassination"
    ut_mirrored_location: str|None = None

    def can_reach(self, state: CollectionState) -> bool:
        if self.ut_mirrored_location is None or not hasattr(state.multiworld, "hitman_client_checked_locations"):
            return super().can_reach(state)

        return location_table[self.ut_mirrored_location].id + base_id in state.multiworld.hitman_client_checked_locations


@dataclass
class LocationTableEntry:
    id: int
    inclusion_conditions: list[Condition]
    location_groups: list[str]
    def is_allowed(self, enabled_entitlements:list[str]):
        return len(self.fulfilled_conditions(enabled_entitlements)) != 0
    def fulfilled_conditions(self, enabled_entitlements:list[str]):
        return list(condition for condition in self.inclusion_conditions if condition.is_fulfilled(enabled_entitlements))
    def get_rule(self, enabled_entitlements:list[str]):
        result_rule = False_()
        for condition in self.fulfilled_conditions(enabled_entitlements):
            rule = HasAll(*condition.required_items)
            if len(condition.required_item_groups)!=0:
                for group in condition.required_item_groups:
                    rule &= HasGroup(group)
            result_rule |= rule
        return result_rule
    def get_required_item_groups(self, enabled_entitlements:list[str]):
        required_groups = list()
        for condition in self.fulfilled_conditions(enabled_entitlements):
            required_groups.extend(condition.required_item_groups)
        return required_groups
    def get_required_items(self, enabled_entitlements:list[str]):
        required_items = list()
        for condition in self.fulfilled_conditions(enabled_entitlements):
            required_items.extend(condition.required_items)
        return required_items

