for exception in itemsanity_exceptions:
    split_item_pickup_location_table["Itempickup - "+goal_table[exception.location]+" - "+exception.itemname].inclusion_conditions[0].require_none.append(exception.added_restriction)
    for condition in item_pickup_location_table["Itempickup - "+exception.itemname].inclusion_conditions:
        if exception.location in condition.require_all:
            condition.require_none.append(exception.added_restriction)

disguise_location_table["Disguise - Mendoza - 47's Signature Suit with Gloves"].inclusion_conditions[0].require_none.extend(["SKIP_LOCATIONS_WITH_WAIT_TIMES", "SKIP_LOCATIONS_WITH_EXTRA_STEPS", "SKIP_LOCATIONS_THAT_REQUIRE_OTHER_ITEM", "mendoza_no_pacification"])

#chongqing+vanilla targets+no agility makes reactor core impossible => require startinglocation which skips reactor
for name in level_completion_location_table:
    if "Chongqing" in name:
        new_conditions = []
        for condition in level_completion_location_table[name].inclusion_conditions:
            new_condition = deepcopy(condition)
            condition.require_none = ["chongqing_need_to_skip_datacore"]
            new_condition.required_items.append("Starting Location - Chongqing - River-side Walkway")
            new_condition.require_all.append("chongqing_need_to_skip_datacore")
            new_conditions.append(new_condition)
        level_completion_location_table[name].inclusion_conditions += new_conditions

#Small Pumpkin only exists on H3
item_pickup_location_table["Itempickup - Small Pumpkin"].inclusion_conditions[0].require_none.extend(["H1_BASE", "H2_BASE"])
split_item_pickup_location_table["Itempickup - Colorado - Small Pumpkin"].inclusion_conditions[0].require_none.extend(["H1_BASE", "H2_BASE"])

location_table = level_completion_location_table | item_pickup_location_table | split_item_pickup_location_table | disguise_location_table | target_kill_location_table

#Dubai+no agility spawns outside with no way of entering the level, always require Atrium in this case
for name in location_table:
    new_conditions = []
    for condition in location_table[name].inclusion_conditions:
        if "dubai" in condition.require_all:
            new_condition = deepcopy(condition)
            condition.require_none.append("dubai_no_agility")
            new_condition.require_all.append("dubai_no_agility")
            new_condition.required_items.append("Starting Location - Dubai - Atrium Lobby") #TODO: could allow any entrance, but worried about saso
            new_conditions.append(new_condition)
    location_table[name].inclusion_conditions += new_conditions

